export type ProviderIconComponent = ComponentType<SVGProps<SVGSVGElement>>

export const PROVIDER_ICONS: Partial<
  Record<CatalogProviderId, ProviderIconComponent>
> = {
  openai: OpenAiIcon,
  anthropic: AnthropicIcon,
  google: GoogleIcon,
  alibaba: AlibabaIcon,
  deepseek: DeepSeekIcon,
  meta: MetaIcon,
  mistral: MistralIcon,
  minimax: MinimaxIcon,
  moonshotai: MoonshotIcon,
  xai: XAiIcon,
  xiaomi: XiaomiIcon,
  zai: ZaiIcon,
}

export function getProviderIcon(
  providerId: CatalogProviderId,
): ProviderIconComponent | undefined {
  return PROVIDER_ICONS[providerId]
}
